"use client";

import { Menu as MenuPrimitive } from "@base-ui/react/menu";
import { CheckIcon, ChevronRightIcon, CircleIcon } from "lucide-react";
import { styles } from "./dropdown-menu.stylex";

import { cx, x } from "@/lib/utils";

const hidden = (s: string | undefined) => s === "starting" || s === "ending";

const DropdownMenu = (props: React.ComponentProps<typeof MenuPrimitive.Root>) => (
  <MenuPrimitive.Root data-slot="dropdown-menu" {...props} />
);

const DropdownMenuPortal = (
  props: React.ComponentProps<typeof MenuPrimitive.Portal>
) => <MenuPrimitive.Portal data-slot="dropdown-menu-portal" {...props} />;

const DropdownMenuTrigger = (
  props: React.ComponentProps<typeof MenuPrimitive.Trigger>
) => <MenuPrimitive.Trigger data-slot="dropdown-menu-trigger" {...props} />;

const DropdownMenuGroup = (
  props: React.ComponentProps<typeof MenuPrimitive.Group>
) => <MenuPrimitive.Group data-slot="dropdown-menu-group" {...props} />;

const DropdownMenuRadioGroup = (
  props: React.ComponentProps<typeof MenuPrimitive.RadioGroup>
) => <MenuPrimitive.RadioGroup data-slot="dropdown-menu-radio-group" {...props} />;

const DropdownMenuSub = (
  props: React.ComponentProps<typeof MenuPrimitive.SubmenuRoot>
) => <MenuPrimitive.SubmenuRoot data-slot="dropdown-menu-sub" {...props} />;

const DropdownMenuContent = ({
  className,
  style,
  sideOffset = 4,
  align = "center",
  side = "bottom",
  alignOffset,
  collisionPadding,
  children,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.Popup>, "className"> & {
  className?: string;
  align?: "start" | "center" | "end";
  side?: "top" | "bottom" | "left" | "right";
  alignOffset?: number;
  sideOffset?: number;
  collisionPadding?: number;
}) => (
  <MenuPrimitive.Portal>
    <MenuPrimitive.Positioner
      align={align}
      alignOffset={alignOffset}
      collisionPadding={collisionPadding}
      side={side}
      sideOffset={sideOffset}
    >
      <MenuPrimitive.Popup
        data-slot="dropdown-menu-content"
        className={(state) =>
          cx(
            x(styles.popup, hidden(state.transitionStatus) && styles.popupHidden)
              .className,
            className
          )
        }
        style={style}
        {...props}
      >
        {children}
      </MenuPrimitive.Popup>
    </MenuPrimitive.Positioner>
  </MenuPrimitive.Portal>
);

const DropdownMenuItem = ({
  className,
  style,
  inset,
  variant = "default",
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.Item>, "className"> & {
  className?: string;
  inset?: boolean;
  variant?: "default" | "destructive";
}) => (
  <MenuPrimitive.Item
    data-slot="dropdown-menu-item"
    data-inset={inset ? "" : undefined}
    data-variant={variant}
    className={(state) =>
      cx(
        x(
          styles.item,
          inset && styles.itemInset,
          variant === "destructive" && styles.itemDestructive,
          state.highlighted &&
            (variant === "destructive"
              ? styles.itemDestructiveHighlighted
              : styles.itemHighlighted),
          state.disabled && styles.itemDisabled
        ).className,
        className
      )
    }
    style={style}
    {...props}
  />
);

const DropdownMenuCheckboxItem = ({
  className,
  style,
  children,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.CheckboxItem>, "className"> & {
  className?: string;
}) => {
  const indicator = x(styles.indicatorWrap);
  const icon = x(styles.icon);
  return (
    <MenuPrimitive.CheckboxItem
      data-slot="dropdown-menu-checkbox-item"
      className={(state) =>
        cx(
          x(
            styles.item,
            styles.itemIndented,
            state.highlighted && styles.itemHighlighted,
            state.disabled && styles.itemDisabled
          ).className,
          className
        )
      }
      style={style}
      {...props}
    >
      <span className={indicator.className} style={indicator.style}>
        <MenuPrimitive.CheckboxItemIndicator>
          <CheckIcon className={icon.className} style={icon.style} />
        </MenuPrimitive.CheckboxItemIndicator>
      </span>
      {children}
    </MenuPrimitive.CheckboxItem>
  );
};

const DropdownMenuRadioItem = ({
  className,
  style,
  children,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.RadioItem>, "className"> & {
  className?: string;
}) => {
  const indicator = x(styles.indicatorWrap);
  return (
    <MenuPrimitive.RadioItem
      data-slot="dropdown-menu-radio-item"
      className={(state) =>
        cx(
          x(
            styles.item,
            styles.itemIndented,
            state.highlighted && styles.itemHighlighted,
            state.disabled && styles.itemDisabled
          ).className,
          className
        )
      }
      style={style}
      {...props}
    >
      <span className={indicator.className} style={indicator.style}>
        <MenuPrimitive.RadioItemIndicator>
          <CircleIcon
            style={{ width: "0.5rem", height: "0.5rem", fill: "currentColor" }}
          />
        </MenuPrimitive.RadioItemIndicator>
      </span>
      {children}
    </MenuPrimitive.RadioItem>
  );
};

const DropdownMenuLabel = ({
  className,
  style,
  inset,
  ...props
}: React.ComponentProps<"div"> & { inset?: boolean }) => {
  const p = x(styles.label, inset && styles.labelInset);
  return (
    <div
      data-slot="dropdown-menu-label"
      data-inset={inset ? "" : undefined}
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const DropdownMenuSeparator = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.Separator>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.separator);
  return (
    <MenuPrimitive.Separator
      data-slot="dropdown-menu-separator"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const DropdownMenuShortcut = ({
  className,
  style,
  ...props
}: React.ComponentProps<"span">) => {
  const p = x(styles.shortcut);
  return (
    <span
      data-slot="dropdown-menu-shortcut"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const DropdownMenuSubTrigger = ({
  className,
  style,
  inset,
  children,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.SubmenuTrigger>, "className"> & {
  className?: string;
  inset?: boolean;
}) => {
  const icon = x(styles.icon);
  return (
    <MenuPrimitive.SubmenuTrigger
      data-slot="dropdown-menu-sub-trigger"
      data-inset={inset ? "" : undefined}
      className={(state) =>
        cx(
          x(
            styles.item,
            inset && styles.itemInset,
            state.highlighted && styles.itemHighlighted
          ).className,
          className
        )
      }
      style={style}
      {...props}
    >
      {children}
      <ChevronRightIcon
        className={icon.className}
        style={{ ...icon.style, marginLeft: "auto" }}
      />
    </MenuPrimitive.SubmenuTrigger>
  );
};

const DropdownMenuSubContent = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof MenuPrimitive.Popup>, "className"> & {
  className?: string;
}) => (
  <MenuPrimitive.Portal>
    <MenuPrimitive.Positioner>
      <MenuPrimitive.Popup
        data-slot="dropdown-menu-sub-content"
        className={(state) =>
          cx(
            x(styles.popup, hidden(state.transitionStatus) && styles.popupHidden)
              .className,
            className
          )
        }
        style={style}
        {...props}
      />
    </MenuPrimitive.Positioner>
  </MenuPrimitive.Portal>
);

export {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuPortal,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuSeparator,
  DropdownMenuShortcut,
  DropdownMenuSub,
  DropdownMenuSubContent,
  DropdownMenuSubTrigger,
  DropdownMenuTrigger,
};

import * as stylex from "@stylexjs/stylex";
import { colors, radius } from "../tokens.stylex";

export const styles = stylex.create({
  popup: {
    backgroundColor: colors.popover,
    color: colors.popoverForeground,
    borderRadius: radius.md,
    borderWidth: "1px",
    borderStyle: "solid",
    borderColor: colors.border,
    padding: "0.25rem",
    minWidth: "8rem",
    overflowX: "hidden",
    overflowY: "auto",
    boxShadow:
      "0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1)",
    outline: "none",
    zIndex: 50,
    opacity: 1,
    transform: "scale(1)",
    transformOrigin: "var(--transform-origin)",
    transition: "opacity 0.15s ease-in-out, transform 0.15s ease-in-out",
  },
  popupHidden: {
    opacity: 0,
    transform: "scale(0.95)",
  },
  item: {
    display: "flex",
    cursor: "default",
    alignItems: "center",
    gap: "0.5rem",
    borderRadius: "0.125rem",
    paddingLeft: "0.5rem",
    paddingRight: "0.5rem",
    paddingTop: "0.375rem",
    paddingBottom: "0.375rem",
    fontSize: "0.875rem",
    outline: "none",
    userSelect: "none",
    position: "relative",
    transition: "background-color 0.1s ease, color 0.1s ease",
  },
  itemInset: {
    paddingLeft: "2rem",
  },
  itemDestructive: {
    color: colors.destructive,
  },
  itemHighlighted: {
    backgroundColor: colors.accent,
    color: colors.accentForeground,
  },
  itemDestructiveHighlighted: {
    backgroundColor: `color-mix(in oklab, ${colors.destructive} 10%, transparent)`,
    color: colors.destructive,
  },
  itemDisabled: {
    pointerEvents: "none",
    opacity: 0.5,
  },
  indicatorWrap: {
    position: "absolute",
    left: "0.5rem",
    display: "flex",
    width: "0.875rem",
    height: "0.875rem",
    alignItems: "center",
    justifyContent: "center",
    pointerEvents: "none",
  },
  itemIndented: {
    paddingLeft: "2rem",
  },
  label: {
    paddingLeft: "0.5rem",
    paddingRight: "0.5rem",
    paddingTop: "0.375rem",
    paddingBottom: "0.375rem",
    fontSize: "0.875rem",
    fontWeight: 600,
    color: colors.foreground,
  },
  labelInset: {
    paddingLeft: "2rem",
  },
  separator: {
    marginLeft: "-0.25rem",
    marginRight: "-0.25rem",
    marginTop: "0.25rem",
    marginBottom: "0.25rem",
    height: "1px",
    backgroundColor: colors.border,
  },
  shortcut: {
    marginLeft: "auto",
    fontSize: "0.75rem",
    letterSpacing: "0.05em",
    opacity: 0.6,
    color: colors.mutedForeground,
  },
  icon: {
    width: "1rem",
    height: "1rem",
  },
});
